import pandas as pd
import numpy as np
from collections import defaultdict

# Sample dataset: Play Tennis decision based on weather
data = {
    'Outlook': ['Sunny', 'Sunny', 'Overcast', 'Rainy', 'Rainy', 'Rainy', 'Overcast', 'Sunny', 'Sunny', 'Rainy', 'Sunny', 'Overcast', 'Overcast', 'Rainy'],
    'Temperature': ['Hot', 'Hot', 'Hot', 'Mild', 'Cool', 'Cool', 'Mild', 'Mild', 'Mild', 'Mild', 'Hot', 'Mild', 'Cool', 'Mild'],
    'Humidity': ['High', 'High', 'High', 'High', 'Normal', 'Normal', 'Normal', 'High', 'Normal', 'Normal', 'Normal', 'High', 'Normal', 'High'],
    'Wind': ['Weak', 'Strong', 'Weak', 'Weak', 'Weak', 'Strong', 'Strong', 'Weak', 'Weak', 'Weak', 'Strong', 'Strong', 'Weak', 'Strong'],
    'Play': ['No', 'No', 'Yes', 'Yes', 'Yes', 'No', 'Yes', 'No', 'Yes', 'Yes', 'Yes', 'Yes', 'Yes', 'No']
}

df = pd.DataFrame(data)

class NaiveBayesFromScratch:
    def __init__(self):
        self.class_priors = {}
        self.feature_probs = {}

    def fit(self, df, target_col):
        # Calculate class priors P(Play=Yes) and P(Play=No)
        self.target_col = target_col
        class_counts = df[target_col].value_counts()
        total = len(df)

        for cls in class_counts.index:
            self.class_priors[cls] = class_counts[cls] / total

        # Calculate conditional probabilities P(Feature=Value|Class)
        features = [col for col in df.columns if col != target_col]

        for feature in features:
            self.feature_probs[feature] = {}
            for value in df[feature].unique():
                self.feature_probs[feature][value] = {}
                for cls in class_counts.index:
                    # Count occurrences where feature=value AND class=cls
                    subset = df[df[target_col] == cls]
                    count = len(subset[subset[feature] == value])
                    # Laplace smoothing (add 1)
                    total_features = len(subset[feature].unique())
                    self.feature_probs[feature][value][cls] = (count + 1) / (len(subset) + total_features)

    def predict_single(self, instance):
        posteriors = {}

        for cls in self.class_priors.keys():
            posterior = self.class_priors[cls]
            for feature, value in instance.items():
                if value in self.feature_probs[feature]:
                    posterior *= self.feature_probs[feature][value][cls]
            posteriors[cls] = posterior

        return max(posteriors, key=posteriors.get)

    def predict(self, df_test):
        predictions = []
        for idx, row in df_test.iterrows():
            instance = {col: row[col] for col in df_test.columns if col != self.target_col}
            predictions.append(self.predict_single(instance))
        return predictions

# Train the model
nb = NaiveBayesFromScratch()
nb.fit(df, 'Play')

# Test prediction
test_data = pd.DataFrame([{
    'Outlook': 'Sunny',
    'Temperature': 'Hot',
    'Humidity': 'High',
    'Wind': 'Weak'
}])

print("Class Priors:", nb.class_priors)
print("\nConditional Probabilities for 'Outlook=Sunny':")
print(nb.feature_probs['Outlook']['Sunny'])
print("\nPrediction for test instance:", nb.predict_single(test_data.iloc[0]))
